const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017';
const DATABASE_NAME = process.env.DATABASE_NAME || 'querydb';

let db;

MongoClient.connect(MONGODB_URI)
  .then(client => {
    db = client.db(DATABASE_NAME);
    console.log('Connected to MongoDB');
  })
  .catch(err => {
    console.error('Failed to connect to MongoDB:', err);
    process.exit(1);
  });

function sanitizeQuery(query) {
  if (!query || typeof query !== 'object') {
    return {};
  }

  const sanitized = {};
  
  for (const [key, value] of Object.entries(query)) {
    if (key.startsWith('$')) {
      continue;
    }

    if (value && typeof value === 'object') {
      if (Array.isArray(value)) {
        sanitized[key] = value;
      } else {
        const sanitizedValue = {};
        for (const [operator, operatorValue] of Object.entries(value)) {
          const allowedOperators = [
            '$eq', '$ne', '$gt', '$gte', '$lt', '$lte',
            '$in', '$nin', '$exists', '$regex', '$options',
            '$elemMatch', '$size', '$all', '$type'
          ];
          
          if (allowedOperators.includes(operator)) {
            if (operator === '$regex' && typeof operatorValue === 'string') {
              sanitizedValue[operator] = operatorValue;
            } else if (operator === '$options' && typeof operatorValue === 'string') {
              sanitizedValue[operator] = operatorValue;
            } else {
              sanitizedValue[operator] = operatorValue;
            }
          }
        }
        sanitized[key] = sanitizedValue;
      }
    } else {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

app.post('/api/query/:collection', async (req, res) => {
  try {
    const { collection } = req.params;
    const { filter = {}, projection = {}, sort = {}, limit = 100, skip = 0 } = req.body;

    if (!collection || typeof collection !== 'string') {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    const sanitizedFilter = sanitizeQuery(filter);
    
    const options = {};
    if (Object.keys(projection).length > 0) {
      options.projection = projection;
    }
    if (Object.keys(sort).length > 0) {
      options.sort = sort;
    }
    options.limit = Math.min(parseInt(limit) || 100, 1000);
    options.skip = parseInt(skip) || 0;

    const results = await db.collection(collection)
      .find(sanitizedFilter, options)
      .toArray();

    res.json({
      success: true,
      count: results.length,
      data: results
    });

  } catch (error) {
    console.error('Query error:', error);
    res.status(500).json({ 
      success: false, 
      error: 'Query execution failed',
      message: error.message 
    });
  }
});

